DECLARE @Name_0de96cc7 NVARCHAR(255),
@CategoryID_0de96cc7 UNIQUEIDENTIFIER,
@UserQuestion_0de96cc7 NVARCHAR(MAX),
@Description_0de96cc7 NVARCHAR(MAX),
@SQL_0de96cc7 NVARCHAR(MAX),
@TechnicalDescription_0de96cc7 NVARCHAR(MAX),
