@Feedback_0de96cc7 NVARCHAR(MAX),
@Status_0de96cc7 NVARCHAR(15),
@QualityRank_0de96cc7 INT,
@ExecutionCostRank_0de96cc7 INT,
@UsesTemplate_0de96cc7 BIT,
@AuditQueryRuns_0de96cc7 BIT,
@CacheEnabled_0de96cc7 BIT,
@CacheTTLMinutes_0de96cc7 INT,
@CacheMaxSize_0de96cc7 INT,
@EmbeddingVector_0de96cc7 NVARCHAR(MAX),
@EmbeddingModelID_0de96cc7 UNIQUEIDENTIFIER,
@CacheValidationSQL_0de96cc7 NVARCHAR(MAX),
@SQLDialectID_0de96cc7 UNIQUEIDENTIFIER,
@Reusable_0de96cc7 BIT,
@ID_0de96cc7 UNIQUEIDENTIFIER
SET
  @Name_0de96cc7 = N'GetArtifactVersionsByID'
SET
  @CategoryID_0de96cc7 = '5609FBC7-381C-4F9C-9C74-04B52C1FF3DA'
SET
  @UserQuestion_0de96cc7 = N'What are the full artifact version records for a given set of artifact version IDs?'
SET
  @Description_0de96cc7 = N'Returns artifact version fields (name, content mode, file ref, content, mime) joined with the parent artifact and artifact type (including ToolLibraryClass) for a supplied list of ArtifactVersionIDs.'
SET
  @SQL_0de96cc7 = N'-- Get Artifact Versions By ID - Single optimized query
-- Returns all fields needed to construct InputArtifact records for agent context gathering.
-- Replaces a per-version loop that did two Load() calls (ArtifactVersion + Artifact) per row.
--
-- Parameters:
--   @versionIds: Array of ArtifactVersionIDs (rendered via sqlIn filter)

SELECT
    av.ID as VersionID,
    av.Name as VersionName,
    av.ContentMode,
    av.FileID,
    av.Content,
    av.MimeType,
    av.ForceToolsOnly,

    a.Name as ArtifactName,
    a.Type as TypeName,

    at.ToolLibraryClass,
    at.DefaultDeliveryMode

FROM [${flyway:defaultSchema}].[vwArtifactVersions] av
INNER JOIN [${flyway:defaultSchema}].[vwArtifacts] a ON av.ArtifactID = a.ID
INNER JOIN [${flyway:defaultSchema}].[vwArtifactTypes] at ON a.TypeID = at.ID

WHERE av.ID IN {{ versionIds | sqlIn }}
'
SET
  @TechnicalDescription_0de96cc7 = N'Single-query replacement for AgentRunner.gatherConversationArtifacts per-junction loop that issued two Load() calls per row (MJ: Artifact Versions + MJ: Artifacts). Joins vwArtifactVersions → vwArtifacts → vwArtifactTypes so ToolLibraryClass is available without a third lookup. Accepts a JS array via {{ versionIds | sqlIn }}.'
SET
  @Status_0de96cc7 = N'Approved'
SET
  @QualityRank_0de96cc7 = 9
SET
  @ExecutionCostRank_0de96cc7 = 2
SET
  @UsesTemplate_0de96cc7 = 1
SET
  @AuditQueryRuns_0de96cc7 = 0
SET
  @CacheEnabled_0de96cc7 = 0
