-- Save MJ: Query SQLs (core SP call only)
DECLARE @QueryID_bc31766b UNIQUEIDENTIFIER,
@SQLDialectID_bc31766b UNIQUEIDENTIFIER,
@SQL_bc31766b NVARCHAR(MAX),
@ID_bc31766b UNIQUEIDENTIFIER
SET
  @QueryID_bc31766b = '34D2D4D2-C727-4366-996F-3AAF87FC103E'
SET
  @SQLDialectID_bc31766b = '426915F2-D4FE-4AB9-97A8-39063561DE9F'
SET
  @SQL_bc31766b = N'-- PostgreSQL variant: Get Artifact Versions By ID
-- Mirrors get-artifact-versions-by-id.sql for PG. Differences:
--   * `[${flyway:defaultSchema}].[X]` → `${flyway:defaultSchema}."X"` (schema brackets removed, view names quoted).
--   * Bare PascalCase column refs double-quoted to survive PG''s case-folding.

SELECT
    av."ID" AS "VersionID",
    av."Name" AS "VersionName",
    av."ContentMode",
    av."FileID",
    av."Content",
    av."MimeType",
    av."ForceToolsOnly",

    a."Name" AS "ArtifactName",
    a."Type" AS "TypeName",

    at."ToolLibraryClass",
    at."DefaultDeliveryMode"

FROM ${flyway:defaultSchema}."vwArtifactVersions" av
INNER JOIN ${flyway:defaultSchema}."vwArtifacts" a ON av."ArtifactID" = a."ID"
INNER JOIN ${flyway:defaultSchema}."vwArtifactTypes" at ON a."TypeID" = at."ID"

WHERE av."ID" IN {{ versionIds | sqlIn }}
'
SET
  @ID_bc31766b = '3659bd9a-71af-448e-8567-6e531ba58bba' EXEC [${flyway:defaultSchema}].spUpdateQuerySQL @QueryID = @QueryID_bc31766b,
  @SQLDialectID = @SQLDialectID_bc31766b,
  @SQL = @SQL_bc31766b,
  @ID = @ID_bc31766b;

GO

